/**
 * Returns the pre-computed AnalysisResult for a flow text if (and only if)
 * the text matches one of the built-in samples exactly. Returns null otherwise
 * so the caller falls through to the live API.
 */
export function getSampleResult(flowText: string): AnalysisResult | null {
  const trimmed = flowText.trim()
  for (const [label, text] of Object.entries(SAMPLE_FLOWS)) {
    if (text.trim() === trimmed) {
      return SAMPLE_RESULTS[label] ?? null
    }
  }
  return null
}
